SELECT content
FROM replies
WHERE content = 'Excited for the event! Count me in.';

SELECT views 
FROM user_blogs 
WHERE blog_id = 0;

SELECT u.user_id, r.role_name
FROM users u
JOIN roles r ON u.role_id = r.role_id
WHERE u.reputation_score = (
    SELECT MAX(reputation_score) FROM users
);

SELECT post_id, user_id, created_date
FROM posts
ORDER BY created_date DESC;
